export const TERMS = [
  // ── Attributions (11) ──
  { term:"Attributions", def:"Explanations we generate for the causes of events, others' behavior, and our own behavior.", cat:"Attributions", blank:"causes of events", accept:["attributions","attribution"], example:"When a friend cancels plans, you make an attribution — maybe they're rude (dispositional) or maybe they're sick (situational)." },
  { term:"Dispositional attributions", def:"Explaining someone's behavior by crediting their internal characteristics such as personality traits, motives, or attitudes.", cat:"Attributions", blank:"internal characteristics", accept:["dispositional attributions","dispositional attribution","internal attribution"], example:"Assuming a classmate failed a test because they are lazy is a dispositional attribution." },
  { term:"Situational attributions", def:"Explaining someone's behavior by crediting external factors such as the environment, social pressure, or luck.", cat:"Attributions", blank:"external factors", accept:["situational attributions","situational attribution","external attribution"], example:"Assuming a classmate failed a test because the questions were unfair is a situational attribution." },
  { term:"Explanatory style", def:"A person's habitual way of explaining the events that happen to them, varying along dimensions of internal/external, stable/unstable, and global/specific.", cat:"Attributions", blank:"habitual way of explaining", accept:["explanatory style","attributional style"], example:"Someone with a negative explanatory style might say 'I always fail at everything' after one bad grade." },
  { term:"Optimistic explanatory style", def:"A pattern of attributing negative events to external, unstable, and specific causes, leading to resilience and persistence.", cat:"Attributions", blank:"external, unstable, and specific", accept:["optimistic explanatory style"], example:"After failing a test, an optimist thinks 'That test was unusually hard' rather than 'I'm stupid.'" },
  { term:"Pessimistic explanatory style", def:"A pattern of attributing negative events to internal, stable, and global causes, often associated with helplessness and depression.", cat:"Attributions", blank:"internal, stable, and global", accept:["pessimistic explanatory style"], example:"After failing a test, a pessimist thinks 'I'm terrible at everything and always will be.'" },
  { term:"Actor/observer bias", def:"The tendency to attribute our own behavior to situational factors while attributing others' behavior to dispositional factors.", cat:"Attributions", blank:"our own behavior to situational", accept:["actor/observer bias","actor-observer bias","actor observer bias"], example:"You blame traffic when you're late (situational), but assume a late coworker is irresponsible (dispositional)." },
  { term:"Fundamental attribution error", def:"The tendency to overestimate the influence of dispositional factors and underestimate the influence of situational factors when explaining others' behavior.", cat:"Attributions", blank:"overestimate the influence of dispositional", accept:["fundamental attribution error","fae","correspondence bias"], example:"Seeing someone trip and thinking they're clumsy, rather than noticing the uneven sidewalk, is the fundamental attribution error." },
  { term:"Self-serving bias", def:"The tendency to attribute our successes to internal dispositional factors and our failures to external situational factors.", cat:"Attributions", blank:"successes to internal", accept:["self-serving bias"], example:"A student says 'I aced that test because I'm smart' but 'I failed because the teacher is unfair.'" },
  { term:"Internal locus of control", def:"The belief that one controls one's own fate and that outcomes result from one's own efforts and abilities.", cat:"Attributions", blank:"controls one's own fate", accept:["internal locus of control"], example:"A student with an internal locus of control studies harder after a bad grade, believing effort determines results." },
  { term:"External locus of control", def:"The belief that outside forces such as luck, fate, or powerful others control one's outcomes.", cat:"Attributions", blank:"outside forces", accept:["external locus of control"], example:"A student with an external locus of control blames bad luck for a poor grade rather than lack of studying." },

  // ── Social Perception (8) ──
  { term:"Mere exposure effect", def:"The phenomenon that repeated exposure to a novel stimulus increases liking of that stimulus.", cat:"Social Perception", blank:"repeated exposure", accept:["mere exposure effect","familiarity effect"], example:"A song you initially disliked grows on you after hearing it several times on the radio." },
  { term:"Self-fulfilling prophecy", def:"A belief or expectation that causes a person to act in ways that make the belief come true.", cat:"Social Perception", blank:"make the belief come true", accept:["self-fulfilling prophecy"], example:"A teacher who expects a student to fail gives less attention, and the student actually does fail as a result." },
  { term:"Social comparison", def:"Evaluating one's own abilities, opinions, or traits by comparing oneself to others.", cat:"Social Perception", blank:"comparing oneself to others", accept:["social comparison","social comparison theory"], example:"Checking how your test score compares to your classmates' is an example of social comparison." },
  { term:"Upward social comparison", def:"Comparing oneself to someone who is perceived as better off, which can inspire improvement but also lower self-esteem.", cat:"Social Perception", blank:"someone who is perceived as better off", accept:["upward social comparison"], example:"An amateur runner compares her times to an Olympic athlete's, feeling motivated but also inadequate." },
  { term:"Downward social comparison", def:"Comparing oneself to someone who is perceived as worse off, often to boost self-esteem.", cat:"Social Perception", blank:"someone who is perceived as worse off", accept:["downward social comparison"], example:"After getting a B, a student feels better by comparing to classmates who got Cs and Ds." },
  { term:"Relative deprivation", def:"The perception that one is worse off relative to those with whom one compares oneself, leading to feelings of discontent.", cat:"Social Perception", blank:"worse off relative to those", accept:["relative deprivation"], example:"A person earning a good salary feels dissatisfied after learning their neighbor earns much more." },
  { term:"False consensus effect", def:"The tendency to overestimate the extent to which others share our beliefs, attitudes, and behaviors.", cat:"Social Perception", blank:"overestimate the extent", accept:["false consensus effect"], example:"A person who cheats on taxes assumes most other people cheat too." },
  { term:"Halo effect", def:"The tendency to let an overall positive impression of a person influence judgments about their specific traits.", cat:"Social Perception", blank:"overall positive impression", accept:["halo effect"], example:"People assume an attractive person is also intelligent, kind, and funny because of the halo effect." },

  // ── Prejudice & Discrimination (9) ──
  { term:"Stereotype", def:"A generalized and often oversimplified belief about the characteristics of a particular group of people.", cat:"Prejudice & Discrimination", blank:"generalized and often oversimplified", accept:["stereotype","stereotypes"], example:"Believing all elderly people are bad with technology is a stereotype." },
  { term:"Cognitive load", def:"The total amount of mental effort being used in working memory, which can increase reliance on stereotypes and heuristics.", cat:"Prejudice & Discrimination", blank:"mental effort being used in working memory", accept:["cognitive load"], example:"When multitasking during a stressful day, people are more likely to rely on stereotypes because of high cognitive load." },
  { term:"Prejudice", def:"An unjustifiable and usually negative attitude toward a group and its members, involving stereotyped beliefs, negative feelings, and a predisposition to discriminatory action.", cat:"Prejudice & Discrimination", blank:"unjustifiable and usually negative attitude", accept:["prejudice"], example:"Feeling hostility toward an entire ethnic group without personal experience is an example of prejudice." },
  { term:"Discrimination", def:"Unjustifiable negative behavior toward a group or its members based solely on their group membership.", cat:"Prejudice & Discrimination", blank:"unjustifiable negative behavior", accept:["discrimination"], example:"Refusing to hire a qualified applicant because of their race is discrimination." },
  { term:"Implicit attitudes", def:"Unconscious, automatically activated evaluations that influence behavior without a person's awareness.", cat:"Prejudice & Discrimination", blank:"unconscious, automatically activated", accept:["implicit attitudes","implicit bias","implicit prejudice"], example:"The Implicit Association Test (IAT) reveals that many people have faster associations between certain racial groups and negative words." },
  { term:"Just-world phenomenon", def:"The tendency to believe that the world is fair and that people get what they deserve and deserve what they get.", cat:"Prejudice & Discrimination", blank:"people get what they deserve", accept:["just-world phenomenon","just-world hypothesis","just world phenomenon"], example:"Blaming a homeless person for their situation by assuming they must be lazy reflects the just-world phenomenon." },
  { term:"Out-group homogeneity bias", def:"The tendency to perceive members of an out-group as more similar to one another than members of one's own in-group.", cat:"Prejudice & Discrimination", blank:"more similar to one another", accept:["out-group homogeneity bias","outgroup homogeneity bias","out-group homogeneity"], example:"Saying 'they all look alike' about another ethnic group reflects out-group homogeneity bias." },
  { term:"In-group bias", def:"The tendency to favor one's own group over other groups, giving preferential treatment to those we consider part of 'us.'", cat:"Prejudice & Discrimination", blank:"favor one's own group", accept:["in-group bias","ingroup bias","in-group favoritism"], example:"Students rate essays higher when told the author attends their school rather than a rival school." },
  { term:"Ethnocentrism", def:"The belief that one's own culture or ethnic group is superior to all others, often leading to prejudice against outsiders.", cat:"Prejudice & Discrimination", blank:"own culture or ethnic group is superior", accept:["ethnocentrism"], example:"Judging another culture's customs as 'primitive' based on your own cultural standards is ethnocentrism." },

  // ── Attitudes & Cognition (4) ──
  { term:"Belief perseverance", def:"The tendency to cling to one's initial beliefs even after the basis on which they were formed has been discredited.", cat:"Attitudes & Cognition", blank:"cling to one's initial beliefs", accept:["belief perseverance"], example:"Even after a study is proven fraudulent, people who read it may continue to believe its conclusions." },
  { term:"Confirmation bias", def:"The tendency to search for, interpret, and recall information in a way that confirms one's preexisting beliefs.", cat:"Attitudes & Cognition", blank:"confirms one's preexisting beliefs", accept:["confirmation bias"], example:"A person who believes vaccines are dangerous only reads anti-vaccine websites, ignoring scientific evidence." },
  { term:"Cognitive dissonance", def:"The psychological tension that occurs when a person holds two contradictory cognitions or when behavior conflicts with attitudes, motivating attitude or behavior change.", cat:"Attitudes & Cognition", blank:"two contradictory cognitions", accept:["cognitive dissonance"], example:"A smoker who knows smoking is unhealthy experiences cognitive dissonance and may quit or minimize the health risks." },
  { term:"Social norms", def:"Understood rules for accepted and expected behavior within a group or society that guide social conduct.", cat:"Attitudes & Cognition", blank:"accepted and expected behavior", accept:["social norms","social norm"], example:"Standing facing forward in an elevator is a social norm — violating it makes everyone uncomfortable." },

  // ── Social Influence (13) ──
  { term:"Social influence theory", def:"The study of how the presence, actions, or expectations of others affect an individual's thoughts, feelings, and behaviors.", cat:"Social Influence", blank:"presence, actions, or expectations", accept:["social influence theory","social influence"], example:"Research on social influence explains why people often change their behavior when being watched by others." },
  { term:"Normative social influence", def:"Influence resulting from a person's desire to gain approval or avoid disapproval from others, leading to conformity.", cat:"Social Influence", blank:"gain approval or avoid disapproval", accept:["normative social influence"], example:"A teenager starts vaping because their friends do and they want to fit in — that is normative social influence." },
  { term:"Informational social influence", def:"Influence resulting from one's willingness to accept others' opinions as valid sources of information about reality.", cat:"Social Influence", blank:"accept others' opinions as valid", accept:["informational social influence"], example:"When unsure which fork to use at a formal dinner, you watch others and copy them — that is informational social influence." },
  { term:"Persuasion", def:"The process by which a message induces change in beliefs, attitudes, or behaviors through arguments, appeals, or pressure.", cat:"Social Influence", blank:"change in beliefs, attitudes, or behaviors", accept:["persuasion"], example:"A political campaign ad tries to persuade voters by presenting a candidate's accomplishments." },
  { term:"Elaboration likelihood model", def:"A theory proposing that persuasion occurs through either a central route, involving careful analysis, or a peripheral route, relying on superficial cues.", cat:"Social Influence", blank:"central route", accept:["elaboration likelihood model","elm"], example:"The ELM explains why some people are persuaded by facts and data while others are swayed by a celebrity endorsement." },
  { term:"Central route", def:"Persuasion that occurs when interested people focus on the logic, evidence, and arguments in a message.", cat:"Social Influence", blank:"logic, evidence, and arguments", accept:["central route","central route processing","central route to persuasion"], example:"A consumer reads detailed product reviews and specifications before buying a laptop — central route processing." },
  { term:"Peripheral route", def:"Persuasion that occurs when people are influenced by incidental cues such as a speaker's attractiveness or the number of arguments rather than their quality.", cat:"Social Influence", blank:"incidental cues", accept:["peripheral route","peripheral route processing","peripheral route to persuasion"], example:"Buying a product because a celebrity endorsed it, without evaluating its quality, is peripheral route persuasion." },
  { term:"Foot-in-the-door technique", def:"A compliance strategy that involves getting a person to agree to a small request first, increasing the likelihood they will agree to a larger request later.", cat:"Social Influence", blank:"small request first", accept:["foot-in-the-door technique","foot in the door","foot-in-the-door"], example:"A charity first asks you to sign a petition, then later asks for a donation — foot-in-the-door technique." },
  { term:"Door-in-the-face technique", def:"A compliance strategy that involves making a large request that is expected to be refused, followed by a smaller, more reasonable request.", cat:"Social Influence", blank:"large request that is expected to be refused", accept:["door-in-the-face technique","door in the face","door-in-the-face"], example:"A fundraiser asks for $500 (knowing you'll refuse), then asks for $20 — door-in-the-face technique." },
  { term:"Conformity", def:"Adjusting one's behavior or thinking to match a group standard, as demonstrated in Asch's line experiments.", cat:"Social Influence", blank:"match a group standard", accept:["conformity"], example:"In Asch's experiment, participants gave obviously wrong answers to match the group's incorrect responses." },
  { term:"Obedience", def:"Changing one's behavior in response to a direct command from an authority figure, as studied by Milgram.", cat:"Social Influence", blank:"direct command from an authority figure", accept:["obedience"], example:"In Milgram's experiment, 65% of participants administered the maximum shock level when ordered to by the experimenter." },
  { term:"Collectivism", def:"A cultural orientation that prioritizes group goals over individual goals and emphasizes group identity, interdependence, and social harmony.", cat:"Social Influence", blank:"group goals over individual goals", accept:["collectivism"], example:"In many East Asian cultures, family honor and group success are valued over personal achievement — reflecting collectivism." },
  { term:"Multiculturalism", def:"An approach that values and promotes the coexistence of diverse cultures, encouraging understanding and respect for cultural differences within a society.", cat:"Social Influence", blank:"coexistence of diverse cultures", accept:["multiculturalism"], example:"A school curriculum that includes the histories and traditions of many cultures embodies multiculturalism." },

  // ── Group Dynamics (8) ──
  { term:"Group polarization", def:"The tendency for a group's predominant opinion to become stronger or more extreme after group discussion.", cat:"Group Dynamics", blank:"become stronger or more extreme", accept:["group polarization"], example:"A jury leaning toward acquittal before deliberation is even more confident in acquitting after discussion." },
  { term:"Groupthink", def:"The tendency for cohesive groups to suppress dissent and seek agreement at the expense of critical thinking and realistic appraisal.", cat:"Group Dynamics", blank:"suppress dissent", accept:["groupthink","group think"], example:"The Bay of Pigs invasion is often cited as an example of groupthink — advisors feared challenging President Kennedy's plan." },
  { term:"Diffusion of responsibility", def:"The tendency for each individual in a group to feel less personal responsibility for taking action because responsibility is shared among all members.", cat:"Group Dynamics", blank:"less personal responsibility", accept:["diffusion of responsibility"], example:"In a crowded subway, no one helps a person who fainted because everyone assumes someone else will call for help." },
  { term:"Social loafing", def:"The tendency for individuals to exert less effort when working in a group than when working alone.", cat:"Group Dynamics", blank:"exert less effort", accept:["social loafing"], example:"In a group project, some members slack off because they know others will pick up the slack — that is social loafing." },
  { term:"Deindividuation", def:"The loss of self-awareness and self-restraint in group situations that foster arousal and anonymity.", cat:"Group Dynamics", blank:"loss of self-awareness", accept:["deindividuation"], example:"People in a large, anonymous crowd may engage in vandalism they would never commit alone due to deindividuation." },
  { term:"Social facilitation", def:"The tendency to perform simple or well-learned tasks better and complex or new tasks worse when in the presence of others.", cat:"Group Dynamics", blank:"simple or well-learned tasks better", accept:["social facilitation"], example:"An experienced runner runs faster during a race with spectators, but a novice runner chokes under the same pressure." },
  { term:"Social traps", def:"Situations in which individuals or groups pursue short-term self-interest in ways that are collectively harmful in the long run.", cat:"Group Dynamics", blank:"short-term self-interest", accept:["social traps","social trap"], example:"Overfishing benefits individual fishers now but depletes fish populations for everyone later — a social trap." },
  { term:"Superordinate goals", def:"Shared goals that require cooperation between conflicting groups, helping to reduce intergroup hostility.", cat:"Group Dynamics", blank:"require cooperation", accept:["superordinate goals"], example:"In Sherif's Robbers Cave experiment, rival groups cooperated to fix the camp's water supply — a superordinate goal that reduced hostility." },

  // ── Prosocial Behavior (8) ──
  { term:"Altruism", def:"Unselfish regard for the welfare of others, involving helping behavior with no expectation of personal gain.", cat:"Prosocial Behavior", blank:"no expectation of personal gain", accept:["altruism"], example:"An anonymous donor gives a large sum to charity with no desire for recognition — that is altruism." },
  { term:"Prosocial behavior", def:"Any action intended to benefit another person or society as a whole, such as helping, sharing, or cooperating.", cat:"Prosocial Behavior", blank:"benefit another person", accept:["prosocial behavior","prosocial behaviour"], example:"Holding the door open for a stranger carrying heavy bags is an example of prosocial behavior." },
  { term:"Social debt", def:"The sense of obligation one feels after receiving a favor, which motivates reciprocation.", cat:"Prosocial Behavior", blank:"sense of obligation", accept:["social debt"], example:"After a friend helps you move, you feel social debt and offer to help them paint their house." },
  { term:"Social reciprocity norm", def:"The expectation that people will help those who have helped them, creating a cycle of mutual assistance.", cat:"Prosocial Behavior", blank:"help those who have helped them", accept:["social reciprocity norm","reciprocity norm","norm of reciprocity"], example:"You invite a couple to dinner because they had you over last month — following the social reciprocity norm." },
  { term:"Social responsibility norm", def:"The expectation that people should help those who need help, even without expectation of future repayment.", cat:"Prosocial Behavior", blank:"help those who need help", accept:["social responsibility norm","norm of social responsibility"], example:"Stopping to help a stranded motorist change a tire, even though you'll never see them again, follows the social responsibility norm." },
  { term:"Bystander effect", def:"The tendency for any given bystander to be less likely to give aid when other bystanders are present.", cat:"Prosocial Behavior", blank:"less likely to give aid", accept:["bystander effect"], example:"The murder of Kitty Genovese, where many neighbors heard her screams but no one called police, illustrates the bystander effect." },
  { term:"Situational variables", def:"External environmental factors — such as the number of bystanders, time pressure, or danger — that influence whether a person will help in an emergency.", cat:"Prosocial Behavior", blank:"external environmental factors", accept:["situational variables"], example:"A person is more likely to help someone who collapsed if there are few other people around — a situational variable." },
  { term:"Attentional variables", def:"Factors that determine whether a person notices an event requiring help, such as distraction level or ambiguity of the situation.", cat:"Prosocial Behavior", blank:"notices an event", accept:["attentional variables"], example:"A person wearing headphones might walk right past someone calling for help because attentional variables prevented them from noticing." },

  // ── Work & Organizational Psychology (2) ──
  { term:"Industrial-organizational (I/O) psychologists", def:"Psychologists who apply psychological principles to the workplace, studying productivity, management, employee satisfaction, and organizational behavior.", cat:"Work & Organizational Psychology", blank:"psychological principles to the workplace", accept:["industrial-organizational psychologists","i/o psychologists","io psychologists","industrial-organizational psychology"], example:"An I/O psychologist might redesign an office layout to improve teamwork and employee well-being." },
  { term:"Burnout", def:"A state of physical, emotional, and mental exhaustion caused by prolonged stress, overwork, or lack of control in one's job.", cat:"Work & Organizational Psychology", blank:"physical, emotional, and mental exhaustion", accept:["burnout","burn out"], example:"A nurse working 60-hour weeks for months without breaks may experience burnout, feeling drained and detached from patients." },

  // ── Motivation (12) ──
  { term:"Instincts", def:"Complex, unlearned behaviors that are rigidly patterned throughout a species and triggered by specific stimuli.", cat:"Motivation", blank:"complex, unlearned behaviors", accept:["instincts","instinct","instinct theory"], example:"Birds building nests and salmon swimming upstream to spawn are examples of instinctual behavior." },
  { term:"Drive-Reduction Theory", def:"The theory that a physiological need creates an aroused tension state (a drive) that motivates an organism to satisfy the need and restore homeostasis.", cat:"Motivation", blank:"aroused tension state", accept:["drive-reduction theory","drive reduction theory"], example:"When you haven't eaten all day, hunger creates a drive that motivates you to find food." },
  { term:"Homeostasis", def:"The body's tendency to maintain a balanced and stable internal state by regulating physiological processes such as temperature, hunger, and thirst.", cat:"Motivation", blank:"balanced and stable internal state", accept:["homeostasis"], example:"When your body temperature rises, you sweat to cool down — your body is maintaining homeostasis." },
  { term:"Ghrelin", def:"A hormone produced primarily by the stomach that signals hunger to the brain, stimulating appetite and food intake.", cat:"Motivation", blank:"signals hunger to the brain", accept:["ghrelin"], example:"Ghrelin levels rise before meals, making your stomach growl and motivating you to eat." },
  { term:"Leptin", def:"A hormone secreted by fat cells that signals satiety to the brain, suppressing hunger and regulating energy balance.", cat:"Motivation", blank:"signals satiety to the brain", accept:["leptin"], example:"As fat stores increase, leptin levels rise and signal the hypothalamus to reduce appetite." },
  { term:"Hypothalamus", def:"A small brain structure in the limbic system that regulates hunger, thirst, body temperature, and other basic drives by linking the nervous system to the endocrine system.", cat:"Motivation", blank:"regulates hunger, thirst, body temperature", accept:["hypothalamus"], example:"Damage to the lateral hypothalamus can cause an animal to stop eating, while damage to the ventromedial hypothalamus can cause overeating." },
  { term:"Pituitary Gland", def:"The master endocrine gland, controlled by the hypothalamus, that releases hormones influencing growth, metabolism, and other endocrine glands.", cat:"Motivation", blank:"master endocrine gland", accept:["pituitary gland","pituitary"], example:"The pituitary gland releases growth hormone during childhood and signals the adrenals to produce cortisol during stress." },
  { term:"Belongingness", def:"The innate human need to form and maintain strong, stable interpersonal relationships and feel accepted by others.", cat:"Motivation", blank:"innate human need", accept:["belongingness","need to belong","belongingness need"], example:"Social media's popularity reflects our need for belongingness — we crave likes, comments, and connections." },
  { term:"Incentive Theory", def:"The theory that behavior is motivated by the pull of external rewards and incentives rather than by internal drives alone.", cat:"Motivation", blank:"pull of external rewards", accept:["incentive theory"], example:"A student studies hard not because of internal curiosity but because of the incentive of a scholarship." },
  { term:"Extrinsic Motivation", def:"The desire to perform a behavior to receive promised external rewards or avoid threatened punishment.", cat:"Motivation", blank:"external rewards or avoid threatened punishment", accept:["extrinsic motivation"], example:"An employee works overtime primarily to earn a bonus — that is extrinsic motivation." },
  { term:"Self-Determination Theory", def:"The theory that humans have three innate psychological needs — autonomy, competence, and relatedness — that underlie intrinsic motivation and well-being.", cat:"Motivation", blank:"autonomy, competence, and relatedness", accept:["self-determination theory","sdt"], example:"A teacher who gives students choices in assignments supports their autonomy, boosting intrinsic motivation according to self-determination theory." },
  { term:"Intrinsic Motivation", def:"The desire to perform a behavior effectively for its own sake, driven by internal satisfaction rather than external rewards.", cat:"Motivation", blank:"internal satisfaction", accept:["intrinsic motivation"], example:"A child reads books for the sheer pleasure of learning, not for a grade — that is intrinsic motivation." },

  // ── Arousal & Sensation Seeking (7) ──
  { term:"Arousal Theory", def:"The theory that people are motivated to maintain an optimal level of physiological arousal, seeking stimulation when arousal is too low and calm when it is too high.", cat:"Arousal & Sensation Seeking", blank:"optimal level of physiological arousal", accept:["arousal theory"], example:"A bored student doodles in class to increase arousal, while an anxious student takes deep breaths to decrease it." },
  { term:"Yerkes-Dodson Law", def:"The principle that performance increases with arousal up to a moderate level, after which further arousal impairs performance, with simple tasks benefiting from higher arousal than complex tasks.", cat:"Arousal & Sensation Seeking", blank:"moderate level", accept:["yerkes-dodson law","yerkes dodson law"], example:"A little test anxiety helps you focus, but too much anxiety causes you to freeze — the Yerkes-Dodson Law in action." },
  { term:"Sensation-Seeking Theory", def:"The theory proposed by Zuckerman that individuals differ in their optimal levels of arousal and stimulation, with high sensation seekers drawn to novel and intense experiences.", cat:"Arousal & Sensation Seeking", blank:"novel and intense experiences", accept:["sensation-seeking theory","sensation seeking theory","sensation seeking"], example:"Skydiving enthusiasts and extreme sports athletes tend to score high on sensation-seeking scales." },
  { term:"Thrill Seeking", def:"A dimension of sensation seeking characterized by a desire for exciting, risky physical activities that provide unusual sensations.", cat:"Arousal & Sensation Seeking", blank:"exciting, risky physical activities", accept:["thrill seeking","thrill-seeking"], example:"Bungee jumping and white-water rafting appeal to people high in the thrill-seeking dimension." },
  { term:"Adventure Seeking", def:"A dimension of sensation seeking involving the desire for novel experiences through travel, exploration, and unconventional activities.", cat:"Arousal & Sensation Seeking", blank:"novel experiences through travel", accept:["adventure seeking","adventure-seeking"], example:"Backpacking through remote countries and trying unfamiliar cuisines reflects the adventure-seeking dimension." },
  { term:"Disinhibition", def:"A dimension of sensation seeking characterized by a desire to seek stimulation through social activities, parties, and lowered restraint.", cat:"Arousal & Sensation Seeking", blank:"lowered restraint", accept:["disinhibition"], example:"Someone high in disinhibition might enjoy wild parties and spontaneous social gatherings." },
  { term:"Boredom Susceptibility", def:"A dimension of sensation seeking reflecting an intolerance for repetitive or monotonous experiences and a need for constant novelty.", cat:"Arousal & Sensation Seeking", blank:"intolerance for repetitive", accept:["boredom susceptibility"], example:"A student who quickly loses interest in routine tasks and constantly seeks new projects scores high in boredom susceptibility." },

  // ── Motivational Conflicts (4) ──
  { term:"Lewin's Motivational Conflicts Theory", def:"Kurt Lewin's framework describing three types of psychological conflict that arise when a person must choose between competing goals or motives.", cat:"Motivational Conflicts", blank:"three types of psychological conflict", accept:["lewin's motivational conflicts theory","lewin's conflict theory","motivational conflicts"], example:"Lewin identified approach-approach, avoidance-avoidance, and approach-avoidance as the three basic conflict types." },
  { term:"Approach-Approach Conflicts", def:"A motivational conflict in which a person must choose between two equally attractive and desirable options.", cat:"Motivational Conflicts", blank:"two equally attractive", accept:["approach-approach conflicts","approach-approach conflict","approach approach conflict"], example:"Choosing between two dream colleges that both offered you admission is an approach-approach conflict." },
  { term:"Avoidance-Avoidance Conflicts", def:"A motivational conflict in which a person must choose between two equally undesirable options.", cat:"Motivational Conflicts", blank:"two equally undesirable", accept:["avoidance-avoidance conflicts","avoidance-avoidance conflict","avoidance avoidance conflict"], example:"Choosing between studying for a boring exam or failing the class is an avoidance-avoidance conflict." },
  { term:"Approach-Avoidance Conflicts", def:"A motivational conflict in which a single goal has both attractive and unattractive qualities, creating ambivalence.", cat:"Motivational Conflicts", blank:"both attractive and unattractive", accept:["approach-avoidance conflicts","approach-avoidance conflict","approach avoidance conflict"], example:"Wanting to eat a delicious dessert but fearing weight gain is an approach-avoidance conflict." },

  // ── Emotion (7) ──
  { term:"Emotion", def:"A complex psychological state involving a subjective experience, a physiological response, and a behavioral or expressive response.", cat:"Emotion", blank:"subjective experience", accept:["emotion","emotions"], example:"When you feel fear, your heart races (physiology), you feel scared (subjective experience), and you may run away (behavioral response)." },
  { term:"Affect", def:"The experience of feeling or emotion, used broadly to describe any emotional state — positive, negative, or neutral.", cat:"Emotion", blank:"experience of feeling or emotion", accept:["affect"], example:"A therapist might ask about a client's affect to understand their overall emotional tone during a session." },
  { term:"Facial-Feedback Hypothesis", def:"The theory that facial expressions can influence emotional experiences — for example, smiling can actually make you feel happier.", cat:"Emotion", blank:"facial expressions can influence", accept:["facial-feedback hypothesis","facial feedback hypothesis"], example:"Holding a pen between your teeth (forcing a smile) can make cartoons seem funnier, supporting the facial-feedback hypothesis." },
  { term:"Display Rules", def:"Cultural norms that dictate how, when, and where people should express emotions in social contexts.", cat:"Emotion", blank:"cultural norms", accept:["display rules"], example:"In some cultures, men are discouraged from crying in public — a display rule governing emotional expression." },
  { term:"Elicitors", def:"Events, objects, or situations that trigger or evoke an emotional response in an individual.", cat:"Emotion", blank:"trigger or evoke", accept:["elicitors","elicitor"], example:"A loud, unexpected noise is an elicitor that triggers a startle response and fear." },
  { term:"Broaden-and-Build Theory of Emotion", def:"Barbara Fredrickson's theory that positive emotions broaden one's awareness and encourage novel, exploratory thoughts and actions, building lasting personal resources.", cat:"Emotion", blank:"broaden one's awareness", accept:["broaden-and-build theory","broaden-and-build theory of emotion","broaden and build theory"], example:"Feeling joy while playing encourages creativity and social bonding, which builds lasting friendships — consistent with broaden-and-build theory." },
  { term:"Universal Emotions", def:"The set of basic emotions — typically including happiness, sadness, anger, fear, disgust, and surprise — that are recognized across all human cultures.", cat:"Emotion", blank:"recognized across all human cultures", accept:["universal emotions","basic emotions"], example:"Paul Ekman's research showed that people from isolated tribes could correctly identify facial expressions of the six universal emotions." },

  // ── Psychodynamic Theory (3) ──
  { term:"Psychodynamic Theory", def:"A psychological perspective originating with Freud that emphasizes the role of unconscious forces, early childhood experiences, and inner conflicts in shaping personality and behavior.", cat:"Psychodynamic Theory", blank:"unconscious forces", accept:["psychodynamic theory","psychodynamic perspective","psychoanalytic theory"], example:"A psychodynamic therapist might explore how a patient's childhood relationship with their parents influences their current anxiety." },
  { term:"Preconscious Mind", def:"The level of awareness containing thoughts and memories that are not currently in consciousness but can be readily brought to awareness.", cat:"Psychodynamic Theory", blank:"readily brought to awareness", accept:["preconscious mind","preconscious"], example:"Your phone number is in your preconscious — you're not thinking about it right now, but you can recall it instantly." },
  { term:"Unconscious Mind", def:"In Freudian theory, the reservoir of thoughts, memories, and desires that exist below conscious awareness and significantly influence behavior.", cat:"Psychodynamic Theory", blank:"below conscious awareness", accept:["unconscious mind","unconscious"], example:"Freud believed that repressed traumatic memories in the unconscious mind could manifest as anxiety or phobias." },

  // ── Defense Mechanisms (8) ──
  { term:"Denial", def:"A defense mechanism in which a person refuses to accept reality or acknowledge a threatening situation, blocking awareness of the event.", cat:"Defense Mechanisms", blank:"refuses to accept reality", accept:["denial"], example:"A person diagnosed with a serious illness insists the doctors must be wrong — that is denial." },
  { term:"Displacement", def:"A defense mechanism in which emotional impulses are redirected from the original source to a safer, substitute target.", cat:"Defense Mechanisms", blank:"safer, substitute target", accept:["displacement"], example:"After being yelled at by a boss, a worker goes home and snaps at their spouse — displacing anger to a safer target." },
  { term:"Projection", def:"A defense mechanism in which a person attributes their own unacceptable thoughts, feelings, or motives to another person.", cat:"Defense Mechanisms", blank:"attributes their own unacceptable", accept:["projection"], example:"A person who is dishonest frequently accuses others of lying — projecting their own trait onto others." },
  { term:"Rationalization", def:"A defense mechanism in which a person creates logical-sounding excuses to justify unacceptable behavior or reduce disappointment.", cat:"Defense Mechanisms", blank:"logical-sounding excuses", accept:["rationalization"], example:"A student who didn't get into their first-choice college says 'I didn't really want to go there anyway' — that is rationalization." },
  { term:"Reaction Formation", def:"A defense mechanism in which a person expresses the opposite of their true unconscious feelings in order to conceal them.", cat:"Defense Mechanisms", blank:"opposite of their true unconscious feelings", accept:["reaction formation"], example:"A person who harbors feelings of hostility toward a coworker acts excessively friendly toward them — reaction formation." },
  { term:"Regression", def:"A defense mechanism in which a person retreats to an earlier, more childlike stage of development when facing stress or anxiety.", cat:"Defense Mechanisms", blank:"earlier, more childlike stage", accept:["regression"], example:"A toilet-trained child begins wetting the bed again after the birth of a new sibling — that is regression." },
  { term:"Repression", def:"A defense mechanism in which threatening or painful thoughts and memories are pushed out of conscious awareness into the unconscious mind.", cat:"Defense Mechanisms", blank:"pushed out of conscious awareness", accept:["repression"], example:"A person who experienced childhood abuse may have no memory of the events because they are repressed." },
  { term:"Sublimation", def:"A defense mechanism in which unacceptable impulses are channeled into socially acceptable or productive activities.", cat:"Defense Mechanisms", blank:"socially acceptable or productive activities", accept:["sublimation"], example:"A person channels aggressive urges into competitive sports like boxing — that is sublimation." },

  // ── Humanistic & Social-Cognitive Psychology (5) ──
  { term:"Humanistic Psychology", def:"A psychological perspective that emphasizes the study of the whole person, personal growth, free will, and the striving toward self-actualization.", cat:"Humanistic & Social-Cognitive Psychology", blank:"personal growth, free will", accept:["humanistic psychology","humanistic perspective"], example:"Carl Rogers and Abraham Maslow are key figures in humanistic psychology, which focuses on each person's potential for growth." },
  { term:"Unconditional Regard", def:"According to Carl Rogers, an attitude of total acceptance toward another person regardless of their behavior, fostering healthy psychological development.", cat:"Humanistic & Social-Cognitive Psychology", blank:"total acceptance", accept:["unconditional regard","unconditional positive regard"], example:"A therapist who accepts a client without judgment, even when the client discusses mistakes, shows unconditional positive regard." },
  { term:"Self-Actualizing Tendency", def:"In humanistic psychology, the innate drive to fulfill one's potential, develop abilities, and become the best version of oneself.", cat:"Humanistic & Social-Cognitive Psychology", blank:"fulfill one's potential", accept:["self-actualizing tendency","self-actualization","self actualization"], example:"A musician who spends years mastering their craft to reach their full creative potential is pursuing self-actualization." },
  { term:"Social-Cognitive Theory", def:"The theory proposed by Bandura that personality results from the interaction of cognitive processes, behaviors, and environmental factors through reciprocal determinism.", cat:"Humanistic & Social-Cognitive Psychology", blank:"cognitive processes, behaviors, and environmental factors", accept:["social-cognitive theory","social cognitive theory","social-cognitive perspective"], example:"Bandura's social-cognitive theory explains how a child's belief in their abilities, actions, and environment all shape their personality." },
  { term:"Reciprocal Determinism", def:"Bandura's concept that personal factors, behavioral factors, and environmental factors all interact and influence each other bidirectionally.", cat:"Humanistic & Social-Cognitive Psychology", blank:"interact and influence each other bidirectionally", accept:["reciprocal determinism"], example:"A confident child (personal) speaks up in class (behavior), gets praised by the teacher (environment), and becomes even more confident — reciprocal determinism." },

  // ── Personality & Self (12) ──
  { term:"Self-Concept", def:"A person's overall perception and understanding of who they are, encompassing their beliefs, attributes, and self-knowledge.", cat:"Personality & Self", blank:"overall perception and understanding", accept:["self-concept","self concept"], example:"A teenager who sees herself as athletic, creative, and outgoing has a positive self-concept." },
  { term:"Self-Efficacy", def:"A person's belief in their own ability to successfully perform a specific task or achieve a particular goal.", cat:"Personality & Self", blank:"belief in their own ability", accept:["self-efficacy","self efficacy"], example:"A student with high self-efficacy in math approaches difficult problems with confidence rather than anxiety." },
  { term:"Self-Esteem", def:"A person's overall evaluation of their own worth, encompassing how much they value, approve of, and like themselves.", cat:"Personality & Self", blank:"overall evaluation of their own worth", accept:["self-esteem","self esteem"], example:"A child who receives consistent encouragement from parents tends to develop healthy self-esteem." },
  { term:"Trait Theories", def:"Personality theories that focus on identifying, describing, and measuring individual differences in consistent patterns of behavior, thought, and emotion.", cat:"Personality & Self", blank:"consistent patterns of behavior", accept:["trait theories","trait theory"], example:"Trait theorists like Allport and Cattell classified personality by identifying and measuring specific traits like shyness or assertiveness." },
  { term:"Big Five Theory", def:"The widely accepted trait model that describes personality along five broad dimensions: openness, conscientiousness, extraversion, agreeableness, and emotional stability (neuroticism).", cat:"Personality & Self", blank:"five broad dimensions", accept:["big five theory","big five","big 5","five-factor model","ocean"], example:"A person who scores high on openness and extraversion but low on neuroticism has a specific Big Five personality profile." },
  { term:"Personality Inventories", def:"Standardized questionnaires designed to assess and measure personality traits by having individuals report their own feelings and behaviors.", cat:"Personality & Self", blank:"standardized questionnaires", accept:["personality inventories","personality inventory","personality tests"], example:"The Minnesota Multiphasic Personality Inventory (MMPI) is a widely used personality inventory in clinical settings." },
  { term:"Factor Analysis", def:"A statistical technique used to identify clusters of related items or behaviors that tend to co-occur, often used to identify underlying personality traits.", cat:"Personality & Self", blank:"clusters of related items", accept:["factor analysis"], example:"Researchers used factor analysis on thousands of trait words to discover that personality can be reduced to five major factors." },
  { term:"Openness to Experience", def:"A Big Five personality trait characterized by intellectual curiosity, creativity, appreciation for art, and willingness to try new things.", cat:"Personality & Self", blank:"intellectual curiosity, creativity", accept:["openness to experience","openness"], example:"A person high in openness enjoys visiting art museums, reading philosophy, and traveling to unfamiliar places." },
  { term:"Conscientiousness", def:"A Big Five personality trait characterized by self-discipline, organization, dependability, and a preference for planned rather than spontaneous behavior.", cat:"Personality & Self", blank:"self-discipline, organization", accept:["conscientiousness"], example:"A highly conscientious student keeps a detailed planner, meets every deadline, and reviews notes daily." },
  { term:"Extraversion", def:"A Big Five personality trait characterized by sociability, assertiveness, positive emotionality, and a tendency to seek stimulation in the company of others.", cat:"Personality & Self", blank:"sociability, assertiveness", accept:["extraversion","extroversion"], example:"An extraverted person energizes at parties, enjoys meeting new people, and feels drained by too much time alone." },
  { term:"Agreeableness", def:"A Big Five personality trait characterized by cooperativeness, compassion, trust, and a tendency to be helpful and considerate toward others.", cat:"Personality & Self", blank:"cooperativeness, compassion", accept:["agreeableness"], example:"A highly agreeable person volunteers often, avoids arguments, and goes out of their way to accommodate others." },
  { term:"Emotional Stability", def:"A Big Five personality trait reflecting calmness, emotional resilience, and freedom from persistent negative emotions; the opposite pole of neuroticism.", cat:"Personality & Self", blank:"calmness, emotional resilience", accept:["emotional stability","neuroticism"], example:"A person with high emotional stability stays calm under pressure, while someone low in this trait may become anxious or moody easily." },
];

